.setting-modal{
    display: flex;
    justify-content: center;
    align-items: center;
    position: absolute;
    right: 25px;
    bottom: 10px;
    width: 200px;
    height: 100px;
    border-radius: 10px;
    z-index: 200;
    background-color: var(--bg-elevated);
